  "inlineSchema": "// ============================================================\n// DATENBANK-SCHEMA — mit Verschlüsselung\n// ============================================================\n// Sensible Felder (name, amount) werden als String gespeichert,\n// weil der verschlüsselte Text ein Base64-String ist.\n// In der DB sieht man nur Kauderwelsch.\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id           String @id @default(uuid())\n  email        String @unique\n  password     String\n  name         String\n  encryptedKey String // Encryption Key, verschlüsselt mit dem User-Passwort\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  categories Category[]\n  expenses   Expense[]\n  incomes    Income[]\n  monthInits MonthInit[]\n  reminders  Reminder[]\n\n  @@map(\"users\")\n}\n\nmodel Category {\n  id    String @id @default(uuid())\n  name  String // VERSCHLÜSSELT\n  color String // VERSCHLÜSSELT\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  expenses Expense[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId])\n  @@map(\"categories\")\n}\n\nmodel Expense {\n  id     String @id @default(uuid())\n  name   String // VERSCHLÜSSELT\n  amount String // VERSCHLÜSSELT (String weil Base64)\n\n  categoryId String\n  category   Category @relation(fields: [categoryId], references: [id])\n  tags       String   @default(\"\") // VERSCHLÜSSELT (JSON-Array als String, z.B. '[\"Wocheneinkauf\",\"Online\"]')\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  month       String  @default(\"2026-02\") // NICHT verschlüsselt (für DB-Queries)\n  isRecurring Boolean @default(true)\n\n  reminders Reminder[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId, month])\n  @@map(\"expenses\")\n}\n\nmodel Income {\n  id     String @id @default(uuid())\n  name   String // VERSCHLÜSSELT\n  amount String // VERSCHLÜSSELT\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  month       String  @default(\"2026-02\")\n  isRecurring Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId, month])\n  @@map(\"incomes\")\n}\n\n// Trackt ob ein Monat bereits für einen User initialisiert wurde.\n// Verhindert dass gelöschte Einträge nach einem Refresh wieder auftauchen.\nmodel MonthInit {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  month  String // Format: \"YYYY-MM\"\n  type   String // \"expense\" | \"income\"\n\n  createdAt DateTime @default(now())\n\n  @@unique([userId, month, type])\n  @@index([userId, month])\n  @@map(\"month_inits\")\n}\n\n// ============================================================\n// ERINNERUNGEN — Kündigungserinnerungen für Ausgaben\n// ============================================================\n// reminderDate und daysBefore sind NICHT verschlüsselt (für DB-Queries).\n// note ist verschlüsselt (Zero-Knowledge).\n// expenseId ist optional — Erinnerung überlebt gelöschte Ausgabe (SetNull).\n// ============================================================\nmodel Reminder {\n  id           String   @id @default(uuid())\n  note         String   @default(\"\") // VERSCHLÜSSELT (optionale Notiz)\n  reminderDate DateTime // NICHT verschlüsselt (für DB-Queries)\n  daysBefore   Int      @default(3) // Tage vorher erinnern (0–90)\n  status       String   @default(\"pending\") // \"pending\" | \"done\" | \"dismissed\"\n\n  expenseId String?\n  expense   Expense? @relation(fields: [expenseId], references: [id], onDelete: SetNull)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([userId, status])\n  @@index([userId, reminderDate])\n  @@map(\"reminders\")\n}\n",
